import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import com.google.gson.JsonNull;
import com.google.gson.JsonObject;
import com.google.gson.JsonPrimitive;
import com.google.gson.internal.bind.JsonTreeWriter;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.ArrayList;

public class JsonTreeWriterPeekTest {

    private JsonTreeWriter jsonTreeWriter;
    private Method peekMethod;

    @BeforeEach
    void setUp() throws NoSuchMethodException {
        jsonTreeWriter = new JsonTreeWriter();
        peekMethod = JsonTreeWriter.class.getDeclaredMethod("peek");
        peekMethod.setAccessible(true);
    }

    @Test
    void peek_shouldReturnTopElement_whenStackHasElements() throws InvocationTargetException, IllegalAccessException, NoSuchFieldException {
        // Arrange
        JsonPrimitive element1 = new JsonPrimitive("first");
        JsonPrimitive element2 = new JsonPrimitive("second");

        // Use reflection to access private field 'stack'
        var stackField = JsonTreeWriter.class.getDeclaredField("stack");
        stackField.setAccessible(true);
        @SuppressWarnings("unchecked")
        ArrayList<JsonElement> stack = (ArrayList<JsonElement>) stackField.get(jsonTreeWriter);
        stack.add(element1);
        stack.add(element2);

        // Act
        JsonElement result = (JsonElement) peekMethod.invoke(jsonTreeWriter);

        // Assert
        assertSame(element2, result);
    }

    @Test
    void peek_shouldThrowIndexOutOfBoundsException_whenStackIsEmpty() {
        // stack is empty by default on new JsonTreeWriter instance

        // Act & Assert
        Exception exception = assertThrows(InvocationTargetException.class, () -> {
            peekMethod.invoke(jsonTreeWriter);
        });
        // The cause should be IndexOutOfBoundsException
        assertTrue(exception.getCause() instanceof IndexOutOfBoundsException);
    }
}
